mapper.insert:
CREATE TABLE IF NOT EXISTS "file" (
"id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, -- 文件ID
"name" varchar(120) NOT NULL, -- 文件名
"ext" varchar(40), -- 文件扩展名
"mime" varchar(100) NOT NULL, -- 文件的MIME类型
"hash" char(128) NOT NULL, -- 文件sha512
"uploader" integer NOT NULL, -- 文件上传者
"folder" integer NOT NULL, -- 所属文件夹ID
"size" bigint NOT NULL,
"upload_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP -- 上传时间
);
DO $$
BEGIN
IF NOT EXISTS (
SELECT 1
FROM pg_constraint c
JOIN pg_class t ON t.oid = c.conrelid
JOIN pg_namespace n ON n.oid = t.relnamespace
WHERE c.conname = 'uk_file_path'
AND t.relname = 'file'
AND n.nspname = current_schema()
) THEN
ALTER TABLE "file"
ADD CONSTRAINT "uk_file_path" UNIQUE ("name", "ext", "folder");
END IF;
END$$;

-- 索引（等价于 MySQL 的 KEY）
CREATE INDEX IF NOT EXISTS "idx_file_ext" ON "file" ("ext");
CREATE INDEX IF NOT EXISTS "idx_file_hash" ON "file" ("hash");
CREATE INDEX IF NOT EXISTS "idx_file_upload_time" ON "file" ("upload_time");
CREATE INDEX IF NOT EXISTS "idx_file_uploader" ON "file" ("uploader");
CREATE INDEX IF NOT EXISTS "idx_file_name_ext" ON "file" ("name", "ext");
CREATE INDEX IF NOT EXISTS "idx_file_folder" ON "file" ("folder");
CREATE INDEX IF NOT EXISTS "idx_file_pure_name" ON "file" ("name");
CREATE INDEX IF NOT EXISTS "idx_file_name_ext_id_uploader" ON "file" ("name", "ext", "id", "uploader");

CREATE TABLE IF NOT EXISTS "folder" (
"id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, -- 文件夹ID
"name" varchar(80) NOT NULL, -- 文件夹名称
"parent" integer, -- 父文件夹ID
"creator" integer, -- 创建者ID
"create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP -- 创建时间
);

DO $$
BEGIN
IF NOT EXISTS (
SELECT 1
FROM pg_constraint c
JOIN pg_class t ON t.oid = c.conrelid
JOIN pg_namespace n ON n.oid = t.relnamespace
WHERE c.conname = 'uk_folder_path'
AND t.relname = 'folder'
AND n.nspname = current_schema() -- 或改成 'public'
) THEN
ALTER TABLE "folder"
ADD CONSTRAINT "uk_folder_path" UNIQUE ("name", "parent");
END IF;
END$$;

-- 索引（等价于 MySQL 的 KEY）
CREATE INDEX IF NOT EXISTS "idx_folder_name" ON "folder" ("name");
CREATE INDEX IF NOT EXISTS "idx_folder_parent" ON "folder" ("parent");

-- 1) 枚举类型（等价于 MySQL enum）
DO $$
BEGIN
IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'statistics_action') THEN
CREATE TYPE statistics_action AS ENUM (
'UPLOAD','DELETE','ACCESS','DOWNLOAD','SEARCH','LOGIN','INVITE','REGISTER','FINGERPRINT_SAVE'
);
END IF;
END $$;

-- 2) 表
CREATE TABLE IF NOT EXISTS "statistics" (
"actor" integer, -- 操作者
"action" statistics_action NOT NULL, -- 所做的操作
"params" jsonb, -- 操作的参数（在ACCESS操作中为空）
"time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP, -- 操作的时间

-- 对于下载类型事件的文件ID（由 params->'id' 生成）
-- 注意：params 这里是 varchar，所以先转 jsonb；若 params 可能不是合法 JSON，建议改用 jsonb 字段或加校验。
"download_file_id" integer GENERATED ALWAYS AS (
CASE
WHEN "action" = 'DOWNLOAD' THEN ((("params")::jsonb ->> 'id')::integer)
END
) STORED
);

-- 3) 索引（PostgreSQL 不支持“索引注释”，这里只保留原注释含义对应的索引名）
CREATE INDEX IF NOT EXISTS "idx_statistics_action" ON "statistics" ("action"); -- 操作类型索引
CREATE INDEX IF NOT EXISTS "idx_statistics_actor" ON "statistics" ("actor"); -- 操作者索引
CREATE INDEX IF NOT EXISTS "idx_statistics_time" ON "statistics" ("time"); -- 时间索引
CREATE INDEX IF NOT EXISTS "idx_statistics_download_file_id" ON "statistics" ("download_file_id");
CREATE INDEX IF NOT EXISTS "idx_statistics_action_download_file_id" ON "statistics"
("action","download_file_id");

-- 1) 枚举类型（等价于 MySQL enum）
DO $$
BEGIN
IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'user_auth') THEN
CREATE TYPE user_auth AS ENUM ('admin','user');
END IF;
END $$;

-- 2) 表（注意：user 是 PostgreSQL 关键字/内置对象名，建议使用双引号或改名为 users）
CREATE TABLE IF NOT EXISTS "user" (
"id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, -- 用户ID
"name" varchar(16) NOT NULL, -- 用户名
"password" varchar(40) NOT NULL, -- 用户密码（MD5+SHA1）
"auth" user_auth NOT NULL DEFAULT 'user', -- 用户类型
"banned" boolean NOT NULL DEFAULT FALSE -- 用户是否被封禁
);

-- 3) 约束 / 索引
-- UNIQUE KEY `name_pk` (`name`)
CREATE UNIQUE INDEX IF NOT EXISTS "uk_user_name" ON "user" ("name");

-- UNIQUE KEY `login_index` (`name`, `password`) COMMENT '用户名密码索引'
CREATE UNIQUE INDEX IF NOT EXISTS "uk_user_name_password" ON "user" ("name","password");

-- UNIQUE KEY `id_index` (`id`) COMMENT 'ID索引'
-- PostgreSQL 的 PRIMARY KEY 已经为 id 自动创建唯一索引，这里无需再建；如要“保留同名索引”可取消注释下面这行：
-- CREATE UNIQUE INDEX IF NOT EXISTS "uk_user_id_index" ON "user" ("id");

-- 1) 枚举类型（等价于 MySQL enum）
DO $$
BEGIN
IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'prefs_sort_field') THEN
CREATE TYPE prefs_sort_field AS ENUM (
'ID','NAME','EXT','TIME','UPLOADER','DOWNLOAD_COUNT','SIZE'
);
END IF;
END $$;

-- 2) 表
CREATE TABLE IF NOT EXISTS "prefs" (
"user_id" integer NOT NULL PRIMARY KEY, -- 用户ID
"sort_field" prefs_sort_field, -- 排序方式
"sort_reverse" boolean -- 排序反向（MySQL tinyint -> Pg boolean）
);

CREATE TABLE IF NOT EXISTS "fingerprint" (
"fingerprint" char(32) NOT NULL PRIMARY KEY, -- 指纹数据
"user_id" integer NOT NULL -- 用户ID
);
